fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    let total: i64 = nums.iter().sum();

    if n <= 2 {
        let prime_sum = if n <= 1 {
            0
        } else {
            nums[0] + nums[1]
        };
        return (2 * prime_sum - total).abs();
    }

    let mut is_prime = vec![true; n];
    is_prime[0] = false;
    is_prime[1] = false;

    let mut i = 2;
    while i * i < n {
        if is_prime[i] {
            let mut j = i * i;
            while j < n {
                is_prime[j] = false;
                j += i;
            }
        }
        i += 1;
    }

    let prime_sum: i64 = nums.iter()
        .enumerate()
        .filter(|&(idx, _)| is_prime[idx])
        .map(|(_, &val)| val)
        .sum();

    (2 * prime_sum - total).abs()
}
